//             if (filteredChildren.length > 0) {
//                 acc.push({ ...node, children: filteredChildren })
//             }
//         }
//         return acc
//     }, [])
// }

function filteTree(nodes, query) {
    const lq = query.toLowerCase()
    return nodes.reduce((acc, curr) => {
        if (curr.name.toLowerCase().includes(lq)) {
            acc.push()
        }
    }, [])
}

function Tree({ treeData }) {
    const searchQuery = useTreeStore((state) => state.searchQuery)
    const isSearching = searchQuery.trim().length > 0
    const displayData = isSearching ? filterTree(treeData, searchQuery.trim()) : treeData

    return (
        <div className='tree-container'>
            <ul className='folder'>
                {
                    displayData.map(({ name, id, type, children, isExpanded }) => {
                        return (
                            <TreeNode key={id} id={id} name={name} type={type} children={children} isExpanded={isExpanded} isSearching={isSearching} searchQuery={searchQuery.trim()} />
                        )
                    })
                }
            </ul>
        </div>)

}

export default Tree
